export function formatFinancialYear(startYear: number): string {
  const nextYearShort = (startYear + 1).toString().slice(-2);
  return `${startYear}-${nextYearShort}`;
}

export function getLeaveErrorMessage(err: unknown): string {
  const status = getApiErrorStatus(err);
  const message = getApiErrorMessage(err);

  if (status === 409) {
    if (/already exists|duplicate/i.test(message)) {
      return 'A leave record already exists for this selection.';
    }
    if (/only submitted/i.test(message)) {
      return 'Only submitted leaves can be edited.';
    }
    if (/invalid transition|cannot/i.test(message)) {
      return 'This action is not valid for the current leave status.';
    }
  }

  return message;
}